import{_ as t,o as a,c as d,a2 as o}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Random Image API a veřejná galerie","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/Other/random-image-api-and-public-gallery.md","filePath":"cs-CZ/Other/random-image-api-and-public-gallery.md","lastUpdated":1781962217000}'),r={name:"cs-CZ/Other/random-image-api-and-public-gallery.md"};function n(i,e,s,p,l,c){return a(),d("div",null,[...e[0]||(e[0]=[o(`<h1 id="random-image-api-a-verejna-galerie" tabindex="-1">Random Image API a veřejná galerie <a class="header-anchor" href="#random-image-api-a-verejna-galerie" aria-label="Permalink to &quot;Random Image API a veřejná galerie&quot;">​</a></h1><p>Obě funkce se nastavují v:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings</span></span></code></pre></div><h2 id="random-image-api" tabindex="-1">Random Image API <a class="header-anchor" href="#random-image-api" aria-label="Permalink to &quot;Random Image API&quot;">​</a></h2><p>Random Image API vrací jeden náhodný soubor z vybraných adresářů. Hodí se pro pozadí webu, rotaci avatarů nebo volání náhodných obrázků z externích stránek.</p><p>Po zapnutí použijte:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/random</span></span></code></pre></div><h2 id="nastaveni-random-image-api" tabindex="-1">Nastavení Random Image API <a class="header-anchor" href="#nastaveni-random-image-api" aria-label="Permalink to &quot;Nastavení Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Účel</th></tr></thead><tbody><tr><td>Enable</td><td>Zapne nebo vypne endpoint <code>/random</code>. Při vypnutí je přístup zakázán.</td></tr><tr><td>Directories</td><td>Omezuje adresáře, které může random API používat. Adresáře mimo seznam API nepoužije.</td></tr><tr><td>Call demo</td><td>Vygeneruje odkazy random API, které můžete rovnou zkopírovat.</td></tr></tbody></table><p>Můžete vybrat více adresářů. Pokud jsou povolené jen <code>/landscape/</code> a <code>/portrait/</code>, random API vybírá soubory jen z těchto adresářů a jejich podadresářů.</p><h2 id="parametry-random-image-api" tabindex="-1">Parametry Random Image API <a class="header-anchor" href="#parametry-random-image-api" aria-label="Permalink to &quot;Parametry Random Image API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parametr</th><th>Příklad</th><th>Účel</th></tr></thead><tbody><tr><td><code>dir</code></td><td><code>/landscape/</code></td><td>Určuje náhodný adresář.</td></tr><tr><td><code>content</code></td><td><code>image</code></td><td>Určuje typ média. Použijte <code>image</code>, <code>video</code>, <code>audio</code> nebo kombinace oddělené čárkou.</td></tr><tr><td><code>orientation</code></td><td><code>auto</code></td><td>Filtruje orientaci obrázku. Použijte <code>portrait</code>, <code>landscape</code> nebo <code>auto</code>.</td></tr><tr><td><code>type</code></td><td><code>url</code></td><td>Formát odpovědi. Prázdné znamená redirect, <code>url</code> vrátí textový URL, <code>json</code> vrátí JSON.</td></tr><tr><td><code>origin</code></td><td><code>1</code></td><td>S <code>type=url</code> vrátí plný URL.</td></tr><tr><td><code>age</code></td><td><code>all-ages,r12</code></td><td>Filtruje podle věkového ratingu.</td></tr><tr><td><code>tag</code></td><td><code>wallpaper,sky</code></td><td>Vrátí jen soubory obsahující tyto tagy.</td></tr><tr><td><code>ex</code></td><td><code>private</code></td><td>Vyloučí soubory obsahující tyto tagy.</td></tr></tbody></table><h2 id="formaty-odpovedi" tabindex="-1">Formáty odpovědi <a class="header-anchor" href="#formaty-odpovedi" aria-label="Permalink to &quot;Formáty odpovědi&quot;">​</a></h2><p>Bez <code>type</code> API přesměruje přímo na URL náhodného souboru.</p><p>S <code>type=url</code> vrátí textový URL.</p><p>S <code>type=json</code> vrátí informace o souboru včetně URL, ID souboru, názvu, typu, tagů, ratingu a metadat.</p><h2 id="pravidla-pristupu" tabindex="-1">Pravidla přístupu <a class="header-anchor" href="#pravidla-pristupu" aria-label="Permalink to &quot;Pravidla přístupu&quot;">​</a></h2><p>Random Image API respektuje pravidla veřejného přístupu:</p><table tabindex="0"><thead><tr><th>Pravidlo</th><th>Dopad</th></tr></thead><tbody><tr><td>Omezení adresáře</td><td>Vybrány mohou být jen soubory v povolených adresářích.</td></tr><tr><td>Blocklist</td><td>Soubory na blocklist jsou vyloučené z náhodné množiny.</td></tr><tr><td>Allowlist režim</td><td>Po zapnutí se vracejí jen soubory povolené pro veřejný přístup.</td></tr><tr><td>Věkový rating</td><td>R12, R16, R18 a podobný obsah se filtruje podle aktuálního režimu přístupu.</td></tr></tbody></table><p>Pokud po filtrování nezůstane žádný soubor, API nevrátí odpovídající výsledek.</p><h2 id="cache" tabindex="-1">Cache <a class="header-anchor" href="#cache" aria-label="Permalink to &quot;Cache&quot;">​</a></h2><p>Random Image API cacheuje kandidátní množiny adresářů kvůli rychlosti.</p><p>Po změnách souborů ImgBed aktualizuje verzi cache adresáře a další požadavky množinu kandidátů znovu sestaví. Prázdné adresáře se cacheují krátce, aby se zamezilo opakovaným dotazům.</p><h2 id="verejna-galerie" tabindex="-1">Veřejná galerie <a class="header-anchor" href="#verejna-galerie" aria-label="Permalink to &quot;Veřejná galerie&quot;">​</a></h2><p>Veřejná galerie poskytuje návštěvníkům read-only stránku pro adresáře, které jim chcete zpřístupnit.</p><p>Po zapnutí mohou návštěvníci otevřít:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/directory-name</span></span></code></pre></div><h2 id="nastaveni-verejne-galerie" tabindex="-1">Nastavení veřejné galerie <a class="header-anchor" href="#nastaveni-verejne-galerie" aria-label="Permalink to &quot;Nastavení veřejné galerie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Volba</th><th>Účel</th></tr></thead><tbody><tr><td>Enable</td><td>Zapne nebo vypne veřejnou galerii. Při vypnutí ji návštěvníci nemohou procházet.</td></tr><tr><td>Image loading mode</td><td>Určuje, zda náhledy používají originály nebo miniatury.</td></tr><tr><td>Open directories</td><td>Nastavuje, které adresáře mohou návštěvníci otevřít.</td></tr></tbody></table><h2 id="rezim-nacitani-obrazku" tabindex="-1">Režim načítání obrázků <a class="header-anchor" href="#rezim-nacitani-obrazku" aria-label="Permalink to &quot;Režim načítání obrázků&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Režim</th><th>Účel</th></tr></thead><tbody><tr><td>Original</td><td>Stránka návštěvníka načítá přímo původní soubory.</td></tr><tr><td>Thumbnail</td><td>Stránka návštěvníka preferuje miniatury pro rychlejší načítání.</td></tr></tbody></table><h2 id="otevrene-adresare" tabindex="-1">Otevřené adresáře <a class="header-anchor" href="#otevrene-adresare" aria-label="Permalink to &quot;Otevřené adresáře&quot;">​</a></h2><p>Otevřené adresáře určují, co návštěvníci uvidí.</p><p>Příklad:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/,/2/,/landscape/,/portrait/</span></span></code></pre></div><p>Návštěvníci pak mohou otevřít:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/browse/1</span></span>
<span class="line"><span>https://your-domain.com/browse/2</span></span>
<span class="line"><span>https://your-domain.com/browse/landscape</span></span>
<span class="line"><span>https://your-domain.com/browse/portrait</span></span></code></pre></div><p>Lze otevřít i podadresáře, například <code>/2026/lucky/</code>. Adresáře, které nejsou otevřené, jsou pro návštěvníky blokované.</p><h2 id="funkce-verejne-galerie" tabindex="-1">Funkce veřejné galerie <a class="header-anchor" href="#funkce-verejne-galerie" aria-label="Permalink to &quot;Funkce veřejné galerie&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkce</th><th>Popis</th></tr></thead><tbody><tr><td>Procházení adresářů</td><td>Zobrazení souborů a podadresářů v otevřených adresářích.</td></tr><tr><td>Vyhledávání</td><td>Hledání podle názvu souboru, ID souboru nebo tagů.</td></tr><tr><td>Filtr typu</td><td>Filtrování obrázků, videí, audia nebo jiných souborů.</td></tr><tr><td>Filtr tagů</td><td>Zahrnutí nebo vyloučení vybraných tagů.</td></tr><tr><td>Filtr orientace</td><td>Filtrování obrázků na šířku nebo na výšku.</td></tr><tr><td>Časový filtr</td><td>Filtrování podle rozsahu času uploadu.</td></tr><tr><td>Filtr přípony</td><td>Filtrování podle přípony souboru.</td></tr><tr><td>Kopírování odkazu</td><td>Kopírování přístupových odkazů k souborům.</td></tr><tr><td>Náhled médií</td><td>Zobrazení nebo přehrání obrázků, videí a audia na stránce návštěvníka.</td></tr></tbody></table><h2 id="pravidla-pristupu-verejne-galerie" tabindex="-1">Pravidla přístupu veřejné galerie <a class="header-anchor" href="#pravidla-pristupu-verejne-galerie" aria-label="Permalink to &quot;Pravidla přístupu veřejné galerie&quot;">​</a></h2><p>Veřejná galerie také respektuje pravidla veřejného přístupu:</p><table tabindex="0"><thead><tr><th>Pravidlo</th><th>Dopad</th></tr></thead><tbody><tr><td>Otevřené adresáře</td><td>Zobrazují se jen povolené adresáře.</td></tr><tr><td>Access mode</td><td>Obsah se filtruje podle aktuálního režimu věkového ratingu.</td></tr><tr><td>Allowlist režim</td><td>Po zapnutí se zobrazují jen soubory povolené pro veřejný přístup.</td></tr><tr><td>Blocklist</td><td>Soubory na blocklist jsou skryté.</td></tr></tbody></table>`,43)])])}const v=t(r,[["render",n]]);export{h as __pageData,v as default};
